# --- Sensitive Data Redaction ---

SENSITIVE_FIELDS = {
    'password', 'passwd', 'secret', 'token', 'access_token', 'refresh_token',
    'authorization', 'api_key', 'apikey', 'credit_card', 'card_number',
    'cvv', 'ssn', 'social_security', 'private_key', 'session_id',
    'cookie', 'set-cookie', 'x-api-key', 'x-auth-token',
}

SENSITIVE_PATTERNS = [
    (re.compile(r'(Bearer\s+)\S+', re.IGNORECASE), r'\1[REDACTED]'),
    (re.compile(r'(Basic\s+)\S+', re.IGNORECASE), r'\1[REDACTED]'),
    (re.compile(r'(\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?)\d{4}\b'), r'\1****'),
    (re.compile(r'(eyJ[\w-]+\.eyJ[\w-]+\.[\w-]+)'), '[REDACTED_JWT]'),
]


def redact_value(key, value):
    """Redact sensitive values based on field name."""
    if isinstance(key, str) and key.lower() in SENSITIVE_FIELDS:
        if isinstance(value, str) and len(value) > 0:
            return '[REDACTED]'
        return '[REDACTED]'
    if isinstance(value, str):
        for pattern, replacement in SENSITIVE_PATTERNS:
            value = pattern.sub(replacement, value)
    return value


def redact_dict(data, depth=0, max_depth=10):
    """Recursively redact sensitive fields from a dictionary."""
    if depth > max_depth:
        return '[MAX_DEPTH_EXCEEDED]'
    if isinstance(data, dict):
        return {k: redact_dict(redact_value(k, v), depth + 1, max_depth)
                for k, v in data.items()}
    elif isinstance(data, list):
        return [redact_dict(item, depth + 1, max_depth) for item in data]
    return data


def redact_headers(headers):
    """Redact sensitive headers."""
    return {k: redact_value(k, v) for k, v in headers.items()}


# --- Custom JSON Formatter ---

class JSONFormatter(logging.Formatter):
    """Structured JSON log formatter for easy parsing by log aggregators."""

    def format(self, record):
        log_entry = {
            'timestamp': datetime.now(timezone.utc).isoformat(),
            'level': record.levelname,
            'logger': record.name,
            'message': record.getMessage(),
            'module': record.module,
            'function': record.funcName,
            'line': record.lineno,
        }

        # Add extra fields if present
        for attr in ('request_id', 'method', 'path', 'status_code',
                     'duration_ms', 'remote_addr', 'user_id', 'user_agent',
                     'content_type', 'request_size', 'response_size',
                     'headers', 'request_body', 'query_params', 'error_type',
                     'error_traceback', 'endpoint', 'auth_method',
                     'auth_status'):
            if hasattr(record, attr):
                log_entry[attr] = getattr(record, attr)

        if record.exc_info and record.exc_info[0] is not None:
            log_entry['exception'] = self.formatException(record.exc_info)

        return json.dumps(log_entry, default=str)


# --- Logging Setup ---

def setup_logging(app):
    """Configure comprehensive logging with multiple handlers."""
    log_dir = os.environ.get('LOG_DIR', 'logs')
    os.makedirs(log_dir, exist_ok=True)

    log_level = getattr(logging, os.environ.get('LOG_LEVEL', 'INFO').upper(), logging.INFO)

    # Root logger for the application
    app_logger = logging.getLogger('app')
    app_logger.setLevel(log_level)
    app_logger.handlers.clear()

    # --- Console Handler (human-readable for development) ---
    console_handler = logging.StreamHandler()
    console_handler.setLevel(log_level)
    console_format = logging.Formatter(
        '[%(asctime)s] %(levelname)s [%(name)s:%(funcName)s:%(lineno)d] '
        '%(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )
    console_handler.setFormatter(console_format)
    app_logger.addHandler(console_handler)

    # --- JSON File Handler (structured, for log aggregators) ---
    json_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'app.json.log'),
        maxBytes=50 * 1024 * 1024,  # 50 MB
        backupCount=10,
        encoding='utf-8'
    )
    json_handler.setLevel(log_level)
    json_handler.setFormatter(JSONFormatter())
    app_logger.addHandler(json_handler)

    # --- Error-only File Handler ---
    error_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'errors.log'),
        maxBytes=20 * 1024 * 1024,  # 20 MB
        backupCount=20,
        encoding='utf-8'
    )
    error_handler.setLevel(logging.ERROR)
    error_handler.setFormatter(JSONFormatter())
    app_logger.addHandler(error_handler)

    # --- Access Log Handler ---
    access_logger = logging.getLogger('app.access')
    access_logger.setLevel(logging.INFO)
    access_logger.propagate = True  # Also logs to app handlers

    access_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'access.log'),
        maxBytes=50 * 1024 * 1024,
        backupCount=10,
        encoding='utf-8'
    )
    access_handler.setLevel(logging.INFO)
    access_handler.setFormatter(JSONFormatter())
    access_logger.addHandler(access_handler)

    # --- Security Audit Log ---
    security_logger = logging.getLogger('app.security')
    security_logger.setLevel(logging.INFO)
    security_logger.propagate = True

    security_handler = logging.handlers.RotatingFileHandler(
        os.path.join(log_dir, 'security_audit.log'),
        maxBytes=20 * 1024 * 1024,
        backupCount=30,
        encoding='utf-8'
    )
    security_handler.setLevel(logging.INFO)
    security_handler.setFormatter(JSONFormatter())
    security_logger.addHandler(security_handler)

    return app_logger


